import jwt
from datetime import datetime

def decode_and_verify_jwt(token, secret_key, algorithms=['HS256'], required_claims=None):
    try:
        # Decode the token
        decoded = jwt.decode(
            token,
            secret_key,
            algorithms=algorithms,
            options={"verify_signature": True}
        )
        
        # Verify required claims if provided
        if required_claims:
            for claim, value in required_claims.items():
                if claim not in decoded or decoded[claim] != value:
                    raise ValueError(f"Missing or incorrect claim: {claim}")
        
        return decoded
    
    except jwt.ExpiredSignatureError:
        print("Token has expired")
    except jwt.InvalidTokenError as e:
        print(f"Invalid token: {e}")
    
    return None

# Example usage
token = "your_jwt_token_here"
secret_key = "your_secret_key_here"
required_claims = {"exp": datetime.utcnow().timestamp() + 3600}  # Example claim for expiration

decoded_token = decode_and_verify_jwt(token, secret_key, required_claims=required_claims)
if decoded_token:
    print("Token is valid and contains the following claims:", decoded_token)
else:
    print("Failed to decode or verify token")